import{_ as s,o as i,c as t,ag as a}from"./chunks/framework.DGzMGr_a.js";const p=JSON.parse('{"title":"nextTick / setImmediate / setTimeout 的区别","description":"","frontmatter":{"title":"nextTick / setImmediate / setTimeout 的区别","difficulty":"medium","tags":["nextTick","setImmediate","微任务","宏任务"],"estimate":20},"headers":[],"relativePath":"domains/nodejs/qa/qa-04-nexttick-immediate-timeout.md","filePath":"domains/nodejs/qa/qa-04-nexttick-immediate-timeout.md","lastUpdated":1783504823000}'),n={name:"domains/nodejs/qa/qa-04-nexttick-immediate-timeout.md"};function o(l,e,r,d,c,h){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="问答-04-进阶-nexttick-setimmediate-settimeout-的区别" tabindex="-1">问答 04（进阶）：nextTick / setImmediate / setTimeout 的区别 <a class="header-anchor" href="#问答-04-进阶-nexttick-setimmediate-settimeout-的区别" aria-label="Permalink to &quot;问答 04（进阶）：nextTick / setImmediate / setTimeout 的区别&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p><code>process.nextTick</code>、<code>setImmediate</code>、<code>setTimeout(fn, 0)</code>、<code>Promise.then</code> 四者的执行时机和优先级有什么区别？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>分类</strong></p><ul><li><strong>微任务</strong>：<code>process.nextTick</code>、<code>Promise.then</code>（每个阶段/宏任务后清空）。</li><li><strong>宏任务（挂在事件循环阶段）</strong>：<code>setTimeout</code>（timers 阶段）、<code>setImmediate</code>（check 阶段）。</li></ul><p><strong>优先级 / 时机</strong></p><ol><li><code>process.nextTick</code>：<strong>最高优先级</strong>。当前操作一结束、进入下一阶段之前立即执行。滥用会「饿死」事件循环（nextTick 队列一直不空，I/O 永远得不到执行）。</li><li><code>Promise.then</code>：微任务，紧随 nextTick 队列之后清空。</li><li><code>setTimeout(fn, 0)</code>：在下一轮 <strong>timers</strong> 阶段执行（最小延迟实际约 1ms）。</li><li><code>setImmediate</code>：在 <strong>check</strong> 阶段执行，即 poll 之后。</li></ol><p><strong>经验规律</strong></p><ul><li><code>nextTick</code> 与 Promise 属于「本轮同步栈结束后立即执行」的微任务；<code>setTimeout/setImmediate</code> 属于「下一轮循环」的宏任务。</li><li>在 <strong>I/O 回调内部</strong>：<code>setImmediate</code> 一定早于 <code>setTimeout(0)</code>。</li><li>在主模块顶层：二者顺序不确定。</li></ul><h2 id="追问-1-为什么说滥用-process-nexttick-有风险" tabindex="-1">追问 1：为什么说滥用 <code>process.nextTick</code> 有风险？ <a class="header-anchor" href="#追问-1-为什么说滥用-process-nexttick-有风险" aria-label="Permalink to &quot;追问 1：为什么说滥用 `process.nextTick` 有风险？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>nextTick 队列会在进入事件循环下一阶段前被<strong>完全清空</strong>。如果在 nextTick 回调里又不断添加 nextTick，队列永远非空，事件循环就无法推进到 poll 阶段处理 I/O，导致 <strong>I/O 饥饿</strong>、定时器不触发、程序假死。</li><li>建议：需要「异步但尽快」用 Promise 或 <code>queueMicrotask</code>；需要「让出一轮给 I/O」用 <code>setImmediate</code>。</li></ul><h2 id="追问-2-queuemicrotask-和-process-nexttick、promise-then-是什么关系" tabindex="-1">追问 2：<code>queueMicrotask</code> 和 <code>process.nextTick</code>、<code>Promise.then</code> 是什么关系？ <a class="header-anchor" href="#追问-2-queuemicrotask-和-process-nexttick、promise-then-是什么关系" aria-label="Permalink to &quot;追问 2：`queueMicrotask` 和 `process.nextTick`、`Promise.then` 是什么关系？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><code>queueMicrotask(fn)</code> 是标准 API，把回调放入 <strong>Promise 微任务队列</strong>，时机与 <code>Promise.resolve().then(fn)</code> 基本一致，但不产生 Promise 对象、没有异常被吞的问题（异常会抛到全局）。</li><li>优先级：<code>process.nextTick</code> &gt; <code>queueMicrotask</code> ≈ <code>Promise.then</code>。</li><li>想跨浏览器/Node 通用地调度微任务，用 <code>queueMicrotask</code>；只在 Node 且需最高优先级插队用 <code>nextTick</code>。</li></ul><h2 id="追问-3-如何用它们做「让出主线程、分批处理大任务」" tabindex="-1">追问 3：如何用它们做「让出主线程、分批处理大任务」？ <a class="header-anchor" href="#追问-3-如何用它们做「让出主线程、分批处理大任务」" aria-label="Permalink to &quot;追问 3：如何用它们做「让出主线程、分批处理大任务」？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>用 <code>setImmediate</code> 把大循环切片，避免阻塞事件循环：</li></ul><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> processInChunks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">arr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> end</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Math.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">min</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, arr.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">length</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (; i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> end; i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">++</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">doWork</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(arr[i]);</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> arr.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">length</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setImmediate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> processInChunks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(arr, i));</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ul><li>关键：每处理一批就用 <code>setImmediate</code> 交还控制权，让 poll 阶段的 I/O 回调（如响应请求）得以执行。</li><li>不要用 <code>nextTick</code> 或 <code>Promise</code> 做切片，它们是微任务，不会真正让出给 I/O。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/nodejs/RESOURCES">Node.js 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://nodejs.org/en/docs/guides/event-loop-timers-and-nexttick" target="_blank" rel="noreferrer">Node.js: Event Loop</a>：<code>nextTick</code> 优先级、<code>setImmediate</code> 与 timers 阶段的执行顺序。</li><li><a href="https://nodejs.org/api/process.html#processnexttickcallback-args" target="_blank" rel="noreferrer">Node.js: process.nextTick</a>：微任务队列与「饿死事件循环」风险。</li><li><a href="https://nodejs.org/api/timers.html" target="_blank" rel="noreferrer">Node.js: Timers</a>：<code>setTimeout(fn, 0)</code> 最小延迟与 I/O 回调内的顺序差异。</li></ul>',24)])])}const m=s(n,[["render",o]]);export{p as __pageData,m as default};
